**Handler function** (add as a module-level function in `slack-adapter.ts`):

```typescript
/**
 * Handle a tool approval button click from Slack Block Kit.
 *
 * Publishes an ApprovalResponse to the relay bus and updates the
 * original message to replace the buttons with the decision result.
 *
 * @param body - The block_actions interaction payload
 * @param client - Slack WebClient for message updates
 * @param approved - Whether the user approved (true) or denied (false)
 * @param relay - RelayPublisher for publishing approval responses
 * @param logger - Logger for diagnostics
 */
async function handleApprovalAction(
  body: BlockAction,
  client: import('@slack/web-api').WebClient,
  approved: boolean,
  relay: RelayPublisher,
  logger: RelayLogger,
): Promise<void> {
  const action = body.actions[0];
  if (!action || action.type !== 'button') return;

  let parsed: { toolCallId: string; sessionId: string; agentId: string };
  try {
    parsed = JSON.parse((action as ButtonAction).value);
  } catch {
    logger.error('Failed to parse approval button value');
    return;
  }

  const respondedBy = body.user?.id;

  // Publish approval response to relay bus
  await relay.publish(
    `relay.system.approval.${parsed.agentId}`,
    {
      type: 'approval_response',
      toolCallId: parsed.toolCallId,
      sessionId: parsed.sessionId,
      approved,
      respondedBy,
      platform: 'slack',
    } satisfies ApprovalResponse,
    { from: `relay.human.slack.${body.channel?.id ?? 'unknown'}` },
  );

  // Extract tool name from the original message blocks for the result text
  const toolName = extractToolNameFromBlocks(body.message);
  const resultText = approved
    ? `*Approved* -- \`${toolName}\` (by <@${respondedBy}>)`
    : `*Denied* -- \`${toolName}\` (by <@${respondedBy}>)`;

  try {
    await client.chat.update({
      channel: body.channel!.id,
      ts: body.message!.ts,
      text: resultText,
      blocks: [
        {
          type: 'section',
          text: { type: 'mrkdwn', text: resultText },
        },
      ],
    });
  } catch (err) {
    logger.error('Failed to update approval message:', err);
  }
}

/**
 * Extract tool name from the original Block Kit message blocks.
 *
 * Parses the first section block's mrkdwn text to find the backtick-wrapped
 * tool name (e.g., "`Write`" from "*Tool Approval Required*\n`Write` wants to...").
 *
 * @param message - The original Slack message from the action body
 */
function extractToolNameFromBlocks(
  message: BlockAction['message'],
): string {
  try {
    const blocks = (message as Record<string, unknown>)?.blocks as Array<Record<string, unknown>> | undefined;
    if (!blocks?.[0]) return 'unknown tool';
    const text = ((blocks[0].text as Record<string, unknown>)?.text as string) ?? '';
    const match = text.match(/`([^`]+)`/);
    return match?.[1] ?? 'unknown tool';
  } catch {
    return 'unknown tool';
  }
}
```

