/**
 * Handle a tool approval inline keyboard callback from Telegram.
 *
 * Looks up the full IDs from the callbackIdMap, publishes an ApprovalResponse
 * to the relay bus, and edits the original message to show the result.
 *
 * @param ctx - Grammy callback query context
 * @param relay - RelayPublisher for publishing approval responses
 * @param logger - Logger for diagnostics
 */
async function handleApprovalCallback(
  ctx: import('grammy').CallbackQueryContext<import('grammy').Context>,
  relay: RelayPublisher,
  logger: import('../../types.js').RelayLogger,
): Promise<void> {
  let parsed: { k: string; a: number };
  try {
    parsed = JSON.parse(ctx.callbackQuery.data);
  } catch {
    await ctx.answerCallbackQuery({ text: 'Invalid action' });
    return;
  }

  const ids = callbackIdMap.get(parsed.k);
  if (!ids) {
    await ctx.answerCallbackQuery({ text: 'Approval expired' });
    return;
  }

  const approved = parsed.a === 1;
  callbackIdMap.delete(parsed.k);

  // Publish approval response to relay bus
  await relay.publish(
    `relay.system.approval.${ids.agentId}`,
    {
      type: 'approval_response',
      toolCallId: ids.toolCallId,
      sessionId: ids.sessionId,
      approved,
      respondedBy: String(ctx.from.id),
      platform: 'telegram',
    } satisfies ApprovalResponse,
    { from: `relay.human.telegram.${ctx.chat?.id ?? 'unknown'}` },
  );

  // Extract tool name from original message text
  const toolName = extractToolNameFromMessage(ctx.callbackQuery.message);
  const resultText = approved
    ? `*Approved* -- \`${toolName}\``
    : `*Denied* -- \`${toolName}\``;

  await ctx.answerCallbackQuery({ text: approved ? 'Approved' : 'Denied' });
  await ctx.editMessageText(resultText, { parse_mode: 'Markdown' });
}

/**
 * Extract tool name from a Telegram message text.
 *
 * Parses the message text to find the first backtick-wrapped tool name.
 *
 * @param message - The callback query's original message
 */
function extractToolNameFromMessage(
  message: import('grammy').CallbackQueryContext<import('grammy').Context>['callbackQuery']['message'],
): string {
  try {
    const text = (message as Record<string, unknown>)?.text as string ?? '';
    const match = text.match(/`([^`]+)`/);
    return match?.[1] ?? 'unknown tool';
  } catch {
    return 'unknown tool';
  }
}
```

