import { describe, it, expect, vi, beforeEach } from 'vitest';
import { RelayCore } from '../../relay-core.js';
import type { AgentRuntimeLike } from '../claude-code/types.js';
import type { RelayEnvelope } from '@dorkos/shared/relay-schemas';

describe('Tool Approval Round-Trip Integration', () => {
  let relay: RelayCore;
  let mockAgentManager: AgentRuntimeLike;

  beforeEach(async () => {
    relay = new RelayCore({ dataDir: '/tmp/relay-test-approval' });
    mockAgentManager = {
      ensureSession: vi.fn(),
      sendMessage: vi.fn(),
      getSdkSessionId: vi.fn(),
      approveTool: vi.fn().mockReturnValue(true),
    };
  });

  afterEach(async () => {
    await relay.close();
  });

  it('routes approval_required through relay to approval subscription', async () => {
    // 1. Subscribe to approval responses (CCA adapter role)
    const approvalReceived = new Promise<void>((resolve) => {
      relay.subscribe('relay.system.approval.>', (envelope: RelayEnvelope) => {
        const payload = envelope.payload as Record<string, unknown>;
        if (payload.type === 'approval_response') {
          mockAgentManager.approveTool(
            payload.sessionId as string,
            payload.toolCallId as string,
            payload.approved as boolean,
          );
          resolve();
        }
      });
    });

    // 2. Simulate a chat adapter publishing an approval response
    await relay.publish(
      'relay.system.approval.agent-1',
      {
        type: 'approval_response',
        toolCallId: 'toolu_123',
        sessionId: 'sess-abc',
        approved: true,
        respondedBy: 'U123',
        platform: 'slack',
      },
      { from: 'relay.human.slack.C456' },
    );

    // 3. Verify the subscription fired and approveTool was called
    await approvalReceived;
    expect(mockAgentManager.approveTool).toHaveBeenCalledWith('sess-abc', 'toolu_123', true);
  });

  it('handles denial round-trip', async () => {
    const denialReceived = new Promise<void>((resolve) => {
      relay.subscribe('relay.system.approval.>', (envelope: RelayEnvelope) => {
        const payload = envelope.payload as Record<string, unknown>;
        if (payload.type === 'approval_response') {
          mockAgentManager.approveTool(
            payload.sessionId as string,
            payload.toolCallId as string,
            payload.approved as boolean,
          );
          resolve();
        }
      });
    });

    await relay.publish(
      'relay.system.approval.agent-2',
      {
        type: 'approval_response',
        toolCallId: 'toolu_456',
        sessionId: 'sess-def',
        approved: false,
        respondedBy: '789',
        platform: 'telegram',
      },
      { from: 'relay.human.telegram.12345' },
    );

    await denialReceived;
    expect(mockAgentManager.approveTool).toHaveBeenCalledWith('sess-def', 'toolu_456', false);
  });
});
